import React from "react";
import {
  TabBarContainer,
  TabItem,
  TabIcon,
  TabLabel,
  CartBadge,
} from "./styles";
import { FaHome, FaTh, FaShoppingCart, FaCommentAlt, FaMapMarkerAlt, FaGlobe } from "react-icons/fa";
import { useSelector, useDispatch } from "react-redux";
import { changelanuage } from "../../../redux/restaurant/restaurantActions";
import useBrowserBottomOffset from "../../../utilities/useBrowserBottomOffset";

export default function BottomTabBar({
  activeView,
  showPopup = null,
  onHomeClick,
  hideHome = false,
  hideCategories = false,
  onCategoriesClick,
  onCartClick,
  onContactClick,
  onFeedbackClick,
  onBranchesClick,
  restaurantName,
  branches,
  isProductDetailsOpen = false,
}) {
  const dispatch = useDispatch();
  const bottomOffset = useBrowserBottomOffset();
  const activeLanguage = useSelector(
    (state) => state.restaurant?.[restaurantName]?.activeLanguage || "en"
  );
  const restaurant = useSelector((state) => state.restaurant?.[restaurantName]);
  const cart = useSelector((state) => state.cart?.[restaurantName] || []);
  const itemCount = cart.reduce((total, item) => total + item.quantity, 0);

  const handleLanguageToggle = () => {
    const newLanguage = activeLanguage === "en" ? "ar" : "en";
    dispatch(changelanuage({ name: restaurantName, activeLanguage: newLanguage }));
  };

  // Parse features to gate tabs
  const _features = (() => {
    try {
      const stored = restaurant?.features || "{}";
      return typeof stored === "string" ? JSON.parse(stored) : stored;
    } catch { return {}; }
  })();

  const tabs = [
    {
      id: "home",
      icon: FaHome,
      label: activeLanguage === "en" ? "Home" : "الرئيسية",
      onClick: onHomeClick,
      active: !showPopup && activeView === "home",
    },
    {
      id: "categories",
      icon: FaTh,
      label: activeLanguage === "en" ? "Categories" : "الفئات",
      onClick: onCategoriesClick,
      active: !showPopup && (activeView === "categories" || activeView === "products"),
    },
    {
      id: "cart",
      icon: FaShoppingCart,
      label: activeLanguage === "en" ? "Cart" : "السلة",
      onClick: onCartClick,
      active: showPopup === "cart",
      badge: itemCount > 0 ? itemCount : null,
    },
    {
      id: "branches",
      icon: FaMapMarkerAlt,
      label: activeLanguage === "en" ? "Branches" : "الفروع",
      onClick: onBranchesClick,
      active: showPopup === "location",
    },
    {
      id: "feedback",
      icon: FaCommentAlt,
      label: activeLanguage === "en" ? "Feedback" : "التعليقات",
      onClick: onFeedbackClick,
      active: showPopup === "feedback",
    },
  ].filter(tab => {
    if (hideHome && tab.id === "home") return false;
    if (hideCategories && tab.id === "categories") return false;
    if (tab.id === "branches") return branches && branches.length > 0;
    if (tab.id === "feedback") return _features.feedback === true;
    return true;
  });

  // Show language changer only if restaurant supports both languages
  const showLanguageChanger = restaurant?.languages === "en&ar";

  return (
    <TabBarContainer data-tab-bar $isProductDetailsOpen={isProductDetailsOpen} style={bottomOffset > 0 ? { bottom: `${bottomOffset}px` } : undefined}>
      {tabs.map((tab) => (
        <TabItem
          key={tab.id}
          data-tab={tab.id}
          onClick={tab.onClick}
          $active={tab.active}
          activeLanguage={activeLanguage}
        >
          <TabIcon 
            id={tab.id === "cart" ? "cart-tab-icon" : undefined}
            $isLanguage={false}
            $activeLanguage={activeLanguage}
          >
            <tab.icon data-icon={tab.id} />
            {tab.badge && <CartBadge>{tab.badge}</CartBadge>}
          </TabIcon>
          <TabLabel activeLanguage={activeLanguage}>{tab.label}</TabLabel>
        </TabItem>
      ))}
      
     
    </TabBarContainer>
  );
}
